  ('pukao-64311456-moex-00242', 'pukao-64311456', 'pukao-64311456-moex-112-e718b90b', 'sub-pukao-64311456-02', NULL, 'single_choice', '根據兒童及少年福利與權益保障法的規定，兒童及少年不得吸菸、飲酒、嚼檳榔。任何人均不得 販賣、交付或供應菸、酒、檳榔予兒童及少年。如果有販賣、交付或供應酒或檳榔予兒童及少年 者，將遭受到多少金額的罰鍰？', '["新臺幣1萬元以上10萬元以下", "新臺幣1萬元以上5萬元以下", "新臺幣2萬元以上5萬元以下", "新臺幣2萬元以上10萬元以下"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:34+00:00", "source_pdf_sha1": "c98749f6e262", "answer_pdf_sha1": "d120e8b33bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "405", "s": "0503", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "社會行政"}'::jsonb, NULL),
